import{_ as a,o as e,c as i,a2 as s}from"./chunks/framework.TWA1q3r6.js";const u=JSON.parse('{"title":"阅读指南","description":"","frontmatter":{"title":"阅读指南"},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),r={name:"guide/index.md"};function n(l,t,o,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="阅读指南" tabindex="-1">阅读指南 <a class="header-anchor" href="#阅读指南" aria-label="Permalink to &quot;阅读指南&quot;">​</a></h1><h2 id="这本手册是什么" tabindex="-1">这本手册是什么？ <a class="header-anchor" href="#这本手册是什么" aria-label="Permalink to &quot;这本手册是什么？&quot;">​</a></h2><p>这是一份基于科学文献的育儿物品清单和发展指南，覆盖孕期到5岁。</p><p>我们做了三件事：</p><ol><li>用 AAP/WHO/CDC/NHS 的循证指南判断每件东西<strong>该不该买</strong></li><li>给&quot;该买&quot;的东西匹配<strong>好看又值得</strong>的品牌</li><li>告诉你<strong>什么时候买最划算</strong></li></ol><p>然后把这三层信息融合到每个成长阶段里，沿着时间线一路往前走就好。</p><h2 id="判定标准" tabindex="-1">判定标准 <a class="header-anchor" href="#判定标准" aria-label="Permalink to &quot;判定标准&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标记</th><th>含义</th><th>准入条件</th></tr></thead><tbody><tr><td><span class="verdict verdict-essential">Essential</span></td><td>科学必选</td><td>权威指南明确推荐 + 因果证据（RCT/大样本/法规）</td></tr><tr><td><span class="verdict verdict-conditional">Conditional</span></td><td>按需配置</td><td>合理机制但非刚需，因个体差异决定</td></tr><tr><td><span class="verdict verdict-tax">Cognitive-Tax</span></td><td>智商税</td><td>权威机构反对 / 无RCT / 可低成本替代</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">三个标记怎么用？</p><ul><li><strong><span class="verdict verdict-essential">Essential</span></strong> 是底线清单 —— 预算有限时只买这些就够了</li><li><strong><span class="verdict verdict-conditional">Conditional</span></strong> 看你的具体情况 —— 每个条目都标注了决策条件</li><li><strong><span class="verdict verdict-tax">Cognitive-Tax</span></strong> 建议跳过 —— 都标注了低成本替代方案</li></ul></div><h2 id="关于品牌审美" tabindex="-1">关于品牌审美 <a class="header-anchor" href="#关于品牌审美" aria-label="Permalink to &quot;关于品牌审美&quot;">​</a></h2><p>我们的审美基准：<strong>北欧极简 / 侘寂风 / 中性色系</strong></p><p>预算基准：追求长期持有价值与安全性，像管理优质固收策略一样管理母婴消费。</p><h2 id="关于数据来源" tabindex="-1">关于数据来源 <a class="header-anchor" href="#关于数据来源" aria-label="Permalink to &quot;关于数据来源&quot;">​</a></h2><ul><li><strong>科学证据</strong>：AAP（美国儿科学会）、WHO（世界卫生组织）、CDC（美国疾控中心）、NHS（英国国民健康服务）、CPSC（美国消费品安全委员会）</li><li><strong>价格数据</strong>：2024-2026年天猫/京东/拼多多公开大促记录</li><li><strong>品牌评估</strong>：安全认证 × 设计奖项 × 二手残值 × 用户口碑</li></ul><h2 id="接下来" tabindex="-1">接下来 <a class="header-anchor" href="#接下来" aria-label="Permalink to &quot;接下来&quot;">​</a></h2><p>从 <a href="/linyuhan-baby-guide/stages/prenatal.html">🤰 孕期准备</a> 开始，沿着时间线往前走。或者直接跳到你当前所在的阶段。</p><div class="warning custom-block"><p class="custom-block-title">免责声明</p><p>本手册不构成任何医疗建议或消费推荐。每个孩子都是独立个体，请以你的儿科医生建议为准。</p></div>',17)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
